/// Parse ScaleTransformation from a string. Returns Ok or Error.
let parse (input: string) : Result<TransformationCommandNode, string> =
    match run (transformationCommandParser .>> eof) input with
    | Success (v, _, _) -> Result.Ok v
    | Failure (msg, _, _) -> Result.Error msg
